SELECT model_name, weight_g
FROM coaxial_illumination_line_scan_lens
WHERE weight_g < 500;

SELECT model_name, wd_mm, focus_length_mm
FROM new_series_line_scan_lens_4k7u
WHERE wd_mm BETWEEN 80 AND 120;

SELECT model_name, weight_g
FROM line_scan_lens_8k7u
WHERE weight_g > 400;

SELECT model_name, flange_distance
FROM line_scan_lens_8k5u
WHERE flange_distance = 12;

SELECT model_name, size_diameter_mm, filter_thread_raw
FROM new_series_line_scan_lens_4k7u
WHERE size_diameter_mm < 50 AND filter_thread_raw IS NOT NULL;

SELECT model_name, focus_length_mm
FROM line_scan_lens_16k3_5u
WHERE focus_length_mm = 60;

SELECT model_name, list_price
FROM line_scan_lens_8k5u
ORDER BY list_price ASC;

SELECT model_name, wd_mm, focus_length_mm
FROM line_scan_lens_4k7u
WHERE wd_mm > 300;

SELECT model_name, list_price
FROM line_scan_lens_12k5u
WHERE list_price < (SELECT AVG(list_price) FROM line_scan_lens_12k5u);

SELECT model_name, weight_g
FROM line_scan_lens_8k5u
WHERE weight_g > (
    SELECT AVG(weight_g)
    FROM line_scan_lens_16k5u
);
